import{_ as e,o,c as a,ae as i}from"./chunks/framework.AIcMzs3L.js";const h=JSON.parse('{"title":"AI 项目相似度推荐方案规划","description":"","frontmatter":{},"headers":[],"relativePath":"PROJECT_RECOMMENDATION_PLAN.md","filePath":"PROJECT_RECOMMENDATION_PLAN.md"}'),l={name:"PROJECT_RECOMMENDATION_PLAN.md"};function r(d,t,s,n,c,g){return o(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="ai-项目相似度推荐方案规划" tabindex="-1">AI 项目相似度推荐方案规划 <a class="header-anchor" href="#ai-项目相似度推荐方案规划" aria-label="Permalink to &quot;AI 项目相似度推荐方案规划&quot;">​</a></h1><h2 id="_1-目标与背景-objective-background" tabindex="-1">1. 目标与背景 (Objective &amp; Background) <a class="header-anchor" href="#_1-目标与背景-objective-background" aria-label="Permalink to &quot;1. 目标与背景 (Objective &amp; Background)&quot;">​</a></h2><p><strong>目标</strong>：实现“输入项目名称，搜索出相关度最高的同类型项目”功能。 <strong>背景</strong>：在 <code>data/projects.json</code> 中包含海量 AI 项目，每个项目拥有 <code>name</code>, <code>description</code>, <code>tags</code>, <code>topics</code>, <code>subcategory</code> 等维度。项目目前已接入 <strong>Meilisearch</strong> 作为搜索引擎，这为实现“相似推荐”功能奠定了非常好的基础。</p><h2 id="_2-方案对比-alternatives-considered" tabindex="-1">2. 方案对比 (Alternatives Considered) <a class="header-anchor" href="#_2-方案对比-alternatives-considered" aria-label="Permalink to &quot;2. 方案对比 (Alternatives Considered)&quot;">​</a></h2><p>针对大规模数据进行相似推荐，目前主流方案有以下三种：</p><table tabindex="0"><thead><tr><th style="text-align:left;">方案</th><th style="text-align:left;">实现原理</th><th style="text-align:left;">优点</th><th style="text-align:left;">缺点</th><th style="text-align:left;">适用场景</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>方案 A：基于现有 Meilisearch 的特征检索</strong> (More Like This)</td><td style="text-align:left;">提取目标项目的 <code>tags</code>, <code>topics</code>, <code>subcategory</code>，利用 Meilisearch 构造组合检索词，计算得分排序。</td><td style="text-align:left;">完全复用现有搜索引擎，零额外成本，实现极其简单，响应极快。</td><td style="text-align:left;">仅基于标签字面匹配，无法理解深层语义差异。</td><td style="text-align:left;"><strong>短期最佳推荐</strong>，现有基建可立即满足。</td></tr><tr><td style="text-align:left;"><strong>方案 B：Meilisearch 向量搜索</strong> (Vector Search / Embeddings)</td><td style="text-align:left;">结合 LLM 生成项目描述的向量(Embeddings)，利用 Meilisearch 1.3+ 版本的 Vector Search 功能进行余弦相似度搜索。</td><td style="text-align:left;">语义理解最强（如：能理解“大型语言模型”和“LLM”高度相关），准确度最高。</td><td style="text-align:left;">需要调用大模型 Embedding API，构建数据时有一定耗时和成本。</td><td style="text-align:left;"><strong>中长期最佳演进方案</strong>，适合追求极致推荐效果时接入。</td></tr><tr><td style="text-align:left;"><strong>方案 C：纯前端静态映射表</strong> (Jaccard 相似度预计算)</td><td style="text-align:left;">构建脚本在打包期间，基于项目的 tags 和 topics 离线计算两两之间的相似度，输出一个 <code>related_projects.json</code> 文件供前端加载。</td><td style="text-align:left;">无需依赖后端服务检索，纯静态、部署简单。</td><td style="text-align:left;">随着项目库无限增长，矩阵文件体积会呈 $O(n^2)$ 级膨胀，前端性能会出问题。</td><td style="text-align:left;">数据量小 (&lt;1000) 且不依赖搜索服务的纯静态站。</td></tr></tbody></table><h2 id="_3-推荐实施路径-proposed-solution" tabindex="-1">3. 推荐实施路径 (Proposed Solution) <a class="header-anchor" href="#_3-推荐实施路径-proposed-solution" aria-label="Permalink to &quot;3. 推荐实施路径 (Proposed Solution)&quot;">​</a></h2><p>综合考虑项目目前已有 Meilisearch 基建，推荐采用 <strong>方案 A（基于 Meilisearch 特征检索）作为核心实现</strong>，并为未来保留 <strong>方案 B（向量检索）</strong> 的升级空间。</p><h3 id="阶段一-实现方案-a-当前阶段行动计划" tabindex="-1">阶段一：实现方案 A（当前阶段行动计划） <a class="header-anchor" href="#阶段一-实现方案-a-当前阶段行动计划" aria-label="Permalink to &quot;阶段一：实现方案 A（当前阶段行动计划）&quot;">​</a></h3><p><strong>核心逻辑 (More Like This)</strong>： 如果用户输入了 &quot;AutoGPT&quot;，我们可以提取出它的属性：<code>tags: [&quot;Agent&quot;, &quot;Automation&quot;, &quot;Autonomous&quot;]</code>，<code>topics: [&quot;agentic-ai&quot;, &quot;agents&quot;, &quot;ai&quot;, ...]</code>。将这些关键词组成一段查询文本语料，放进 Meilisearch 搜索，并排除 &quot;AutoGPT&quot; 本身。</p><p><strong>实施步骤</strong>：</p><ol><li><strong>完善搜索服务层 (后端/API 封装)</strong>： <ul><li>增加一个 <code>getSimilarProjects(projectName)</code> 函数。</li><li>第一步：在 Meilisearch 中根据 <code>name</code> 精确查询目标项目，获取该项目的 <code>description</code>, <code>tags</code>, <code>topics</code>, <code>subcategory</code>。</li><li>第二步：拼接搜索词（权重可以通过查询字符串重复次数调整）。例如 <code>query = tags.join(&quot; &quot;) + &quot; &quot; + topics.join(&quot; &quot;) + &quot; &quot; + subcategory</code>。</li><li>第三步：使用拼接好的 query 对 Meilisearch 的 <code>ai_projects</code> 索引进行搜索。并在 filter 参数中加上 <code>name != &#39;目标项目名称&#39;</code>，避免搜出自己。取 Top 5 ~ 10。</li></ul></li><li><strong>前端集成层</strong>： <ul><li>在项目详情页或搜索下拉框中，新增“相关项目 / 猜你喜欢”模块。</li><li>传入用户当前点击或搜索的项目名称，调用相似度接口，将结果渲染为列表或卡片。</li></ul></li></ol><h3 id="阶段二-向方案-b-向量化语义推荐-演进的准备" tabindex="-1">阶段二：向方案 B（向量化语义推荐）演进的准备 <a class="header-anchor" href="#阶段二-向方案-b-向量化语义推荐-演进的准备" aria-label="Permalink to &quot;阶段二：向方案 B（向量化语义推荐）演进的准备&quot;">​</a></h3><p>如果未来对推荐精准度要求极高，可以在构建时加入向量化流程：</p><ol><li>修改 <code>scripts/meilisearch-index.js</code>，增加调用类似 OpenAI 的 <code>text-embedding-3-small</code> 或免费开源的 Embedding 接口。</li><li>开启 Meilisearch 的 <code>vectorStore</code> 设置。</li><li>搜索时，仅需将输入的项目描述转换为向量并调用 Meilisearch 的向量检索 API。</li></ol><h2 id="_4-方案验证与测试-verification-testing" tabindex="-1">4. 方案验证与测试 (Verification &amp; Testing) <a class="header-anchor" href="#_4-方案验证与测试-verification-testing" aria-label="Permalink to &quot;4. 方案验证与测试 (Verification &amp; Testing)&quot;">​</a></h2><ol><li><strong>功能验证</strong>：针对已知相似度的项目（如 <code>AutoGPT</code> 和 <code>opencode</code>）进行查询，验证它们能否在彼此的相关推荐列表中处于前列。</li><li><strong>过滤验证</strong>：验证推荐列表中是否严格排除了基准项目自身。</li><li><strong>性能验证</strong>：基于现有的数千条数据，确保相关项目的二次查询耗时控制在几十毫秒级，不影响页面主体的渲染。</li></ol>',17)])])}const p=e(l,[["render",r]]);export{h as __pageData,p as default};
